import { useEffect, useState, useContext } from "react";
import { useNavigate } from "react-router-dom";
import { getVoterElection } from "../../api/electionsApi";
import { AuthContext } from "../../context/AuthContext";

function Elections() {
  const { user } = useContext(AuthContext);
  const [election, setElection] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    // voter election now comes from backend JWT
    getVoterElection()
      .then(res => setElection(res.data))
      .catch(err => console.error(err));
  }, []);

  if (!election || !election.id) {
    return <p>No election available</p>;
  }

  return (
    <div>
      <h2>Election</h2>

      <p>Status: <b>{election.status}</b></p>

      {election.status === "ONGOING" ? (
        <button onClick={() => navigate("/voter/vote")}>
          Vote Now
        </button>
      ) : (
        <p>Voting is not open yet</p>
      )}
    </div>
  );
}

export default Elections;
